import pytest
import requests

def test_delete_missing_mandatory_field_returns_400(base_url, admin_token):
    headers = {"Authorization": f"Bearer {admin_token}"}

    resp = requests.delete(
        f"{base_url}/api/org-announcements/",
        headers=headers,
    )

    assert resp.status_code in (400, 404), (
        f"Expected 400 or 404 for missing id, got {resp.status_code}"
    )
